import { format, formatDistanceToNow } from 'date-fns';

/**
 * Format a date in standard date format
 * @param {string|Date} date - Date to format
 * @param {string} formatString - Format string (default: 'PP')
 * @returns {string} Formatted date
 */
const formatDate = (date, formatString = 'PP') => {
  if (!date) return 'N/A';
  
  try {
    const dateObj = new Date(date);
    return format(dateObj, formatString);
  } catch (error) {
    console.error('Error formatting date:', error);
    return 'Invalid date';
  }
};

/**
 * Format a date with both date and time
 * @param {string|Date} date - Date to format
 * @returns {string} Formatted date and time
 */
const formatDateTime = (date) => {
  if (!date) return 'N/A';
  
  try {
    const dateObj = new Date(date);
    return format(dateObj, 'PPp'); // Mar 15, 2023, 3:45 PM
  } catch (error) {
    console.error('Error formatting date and time:', error);
    return 'Invalid date';
  }
};

/**
 * Format a date as relative time (e.g., "5 days ago")
 * @param {string|Date} date - Date to format
 * @returns {string} Relative time
 */
const formatRelativeTime = (date) => {
  if (!date) return 'N/A';
  
  try {
    const dateObj = new Date(date);
    return formatDistanceToNow(dateObj, { addSuffix: true });
  } catch (error) {
    console.error('Error formatting relative time:', error);
    return 'Invalid date';
  }
};

/**
 * Format a date for display in application forms
 * @param {string|Date} date - Date to format
 * @returns {string} Date formatted as YYYY-MM-DD for input[type="date"]
 */
const formatForDateInput = (date) => {
  if (!date) return '';
  
  try {
    const dateObj = new Date(date);
    return format(dateObj, 'yyyy-MM-dd');
  } catch (error) {
    console.error('Error formatting date for input:', error);
    return '';
  }
};

/**
 * Get a formatted date range display
 * @param {string|Date} startDate - Start date
 * @param {string|Date} endDate - End date
 * @returns {string} Formatted date range
 */
const formatDateRange = (startDate, endDate) => {
  if (!startDate || !endDate) return 'N/A';
  
  try {
    const startDateObj = new Date(startDate);
    const endDateObj = new Date(endDate);
    return `${format(startDateObj, 'PP')} - ${format(endDateObj, 'PP')}`;
  } catch (error) {
    console.error('Error formatting date range:', error);
    return 'Invalid date range';
  }
};

export {
  formatDate as default,
  formatDateTime,
  formatRelativeTime,
  formatForDateInput,
  formatDateRange
};
